class TypingSession {
  constructor(duration = 60) {
    this.duration = duration;
    this.errors = 0;
    this.correct = 0;
  }

  get accuracy() {
    const total = this.correct + this.errors;
    return total === 0 ? 0 : (this.correct / total) * 100;
  }
}
